import sys

A, B = map(int, sys.stdin.readline().split())

def gcd(a, b):
    if b == 0:
        return a
    else:
        return gcd(b, a % b)

def solve(a, b):
    g = gcd(a, b)
    count = 0
    for i in range(1, int(g ** 0.5) + 1):
        if g % i == 0:
            if gcd(i, g // i) == 1:
                count += 1
            if i * i != g and gcd(g // i, i) == 1:
                count += 1
    return count

print(solve(A, B))

